import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { GHLApiClient } from '@/lib/ghl/api';

export const dynamic = 'force-dynamic';

/**
 * Fetch available locations for the authenticated user
 * GET /api/locations
 */
export async function GET(request: NextRequest) {
  try {
    const cookieStore = await cookies();
    const locationId = cookieStore.get('ghl_location_id')?.value;

    if (!locationId) {
      return NextResponse.json(
        { error: 'No location context found' },
        { status: 401 }
      );
    }

    const apiClient = new GHLApiClient({ locationId });
    const location = await apiClient.getLocation();

    return NextResponse.json({
      locations: [location],
      success: true,
    });
  } catch (error) {
    console.error('Locations fetch error:', error);
    return NextResponse.json(
      { error: 'Failed to fetch locations', success: false },
      { status: 500 }
    );
  }
}