/**
 * GHL OAuth Client
 * 
 * Handles OAuth 2.0 flow with GoHighLevel
 * Server-side only - NEVER expose client secret to browser
 */

import { getScopesForInstall } from './scopes';

export interface OAuthConfig {
  clientId: string;
  clientSecret: string;
  redirectUri: string;
}

export interface TokenResponse {
  access_token: string;
  refresh_token: string;
  token_type: string;
  expires_in: number;
  scope: string;
  locationId?: string;
  companyId?: string;
  userId?: string;
}

export interface UserInfo {
  id: string;
  email: string;
  name: string;
  companyId: string;
  role: string;
}

const GHL_AUTH_URL = 'https://marketplace.gohighlevel.com/oauth/chooselocation';
const GHL_TOKEN_URL = 'https://services.leadconnectorhq.com/oauth/token';
const GHL_USERINFO_URL = 'https://services.leadconnectorhq.com/oauth/userinfo';

/**
 * Get OAuth configuration from environment
 */
export function getOAuthConfig(): OAuthConfig {
  const clientId = process.env.GHL_CLIENT_ID;
  const clientSecret = process.env.GHL_CLIENT_SECRET;
  const redirectUri = process.env.GHL_REDIRECT_URI || process.env.NEXT_PUBLIC_APP_URL + '/oauth/callback';
  
  if (!clientId || !clientSecret) {
    throw new Error('Missing GHL OAuth credentials in environment variables');
  }
  
  return { clientId, clientSecret, redirectUri };
}

/**
 * Generate OAuth authorization URL
 */
export function getAuthorizationUrl(state?: string): string {
  const config = getOAuthConfig();
  const scopes = getScopesForInstall();
  
  const params = new URLSearchParams({
    client_id: config.clientId,
    redirect_uri: config.redirectUri,
    scope: scopes,
    response_type: 'code',
    ...(state && { state }),
  });
  
  return `${GHL_AUTH_URL}?${params.toString()}`;
}

/**
 * Exchange authorization code for access token
 */
export async function exchangeCodeForToken(code: string): Promise<TokenResponse> {
  const config = getOAuthConfig();
  
  const response = await fetch(GHL_TOKEN_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: new URLSearchParams({
      client_id: config.clientId,
      client_secret: config.clientSecret,
      grant_type: 'authorization_code',
      code,
      redirect_uri: config.redirectUri,
    }),
  });
  
  if (!response.ok) {
    const error = await response.text();
    console.error('Token exchange failed:', error);
    throw new Error(`Failed to exchange code for token: ${response.status}`);
  }
  
  return response.json();
}

/**
 * Refresh access token using refresh token
 */
export async function refreshAccessToken(refreshToken: string): Promise<TokenResponse> {
  const config = getOAuthConfig();
  
  const response = await fetch(GHL_TOKEN_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: new URLSearchParams({
      client_id: config.clientId,
      client_secret: config.clientSecret,
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
    }),
  });
  
  if (!response.ok) {
    const error = await response.text();
    console.error('Token refresh failed:', error);
    throw new Error(`Failed to refresh token: ${response.status}`);
  }
  
  return response.json();
}

/**
 * Get user information from GHL
 */
export async function getUserInfo(accessToken: string): Promise<UserInfo> {
  const response = await fetch(GHL_USERINFO_URL, {
    headers: {
      'Authorization': `Bearer ${accessToken}`,
    },
  });
  
  if (!response.ok) {
    throw new Error(`Failed to get user info: ${response.status}`);
  }
  
  return response.json();
}

/**
 * Revoke access token (for uninstall)
 */
export async function revokeToken(token: string): Promise<void> {
  const config = getOAuthConfig();
  
  try {
    await fetch('https://services.leadconnectorhq.com/oauth/revoke', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        client_id: config.clientId,
        client_secret: config.clientSecret,
        token,
      }),
    });
  } catch (error) {
    console.error('Token revocation failed:', error);
    // Don't throw - revocation is best-effort
  }
}